// OAuth Configuration
const OAUTH_CONFIG = {
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID || 'your-client-id',
  clientSecret: process.env.REACT_APP_OAUTH_CLIENT_SECRET || '', // For public clients, this may be empty
  authorizationEndpoint: process.env.REACT_APP_AUTH_ENDPOINT || 'https://auth.example.com/authorize',
  tokenEndpoint: process.env.REACT_APP_TOKEN_ENDPOINT || 'https://auth.example.com/token',
  redirectUri: process.env.REACT_APP_REDIRECT_URI || window.location.origin + '/callback',
  scope: process.env.REACT_APP_OAUTH_SCOPE || 'openid profile email',
  apiBaseUrl: process.env.REACT_APP_API_BASE_URL || 'https://api.example.com',
};

// PKCE Utilities
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  const array = new Uint8Array(length);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => charset[byte % charset.length]).join('');
}

async function generateCodeChallenge(codeVerifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(codeVerifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

// Token Storage Utilities
const TokenStorage = {
  getAccessToken() {
    return localStorage.getItem('oauth_access_token');
  },
  getRefreshToken() {
    return localStorage.getItem('oauth_refresh_token');
  },
  getTokenExpiry() {
    const expiry = localStorage.getItem('oauth_token_expiry');
    return expiry ? parseInt(expiry, 10) : null;
  },
  getIdToken() {
    return localStorage.getItem('oauth_id_token');
  },
  setTokens({ access_token, refresh_token, expires_in, id_token }) {
    if (access_token) {
      localStorage.setItem('oauth_access_token', access_token);
    }
    if (refresh_token) {
      localStorage.setItem('oauth_refresh_token', refresh_token);
    }
    if (expires_in) {
      const expiryTime = Date.now() + expires_in * 1000;
      localStorage.setItem('oauth_token_expiry', expiryTime.toString());
    }
    if (id_token) {
      localStorage.setItem('oauth_id_token', id_token);
    }
  },
  clearTokens() {
    localStorage.removeItem('oauth_access_token');
    localStorage.removeItem('oauth_refresh_token');
    localStorage.removeItem('oauth_token_expiry');
    localStorage.removeItem('oauth_id_token');
    localStorage.removeItem('oauth_code_verifier');
    localStorage.removeItem('oauth_state');
  },
  isTokenExpired() {
    const expiry = this.getTokenExpiry();
    if (!expiry) return true;
    return Date.now() >= expiry - 60000; // 1 minute buffer
  },
  setCodeVerifier(verifier) {
    localStorage.setItem('oauth_code_verifier', verifier);
  },
  getCodeVerifier() {
    return localStorage.getItem('oauth_code_verifier');
  },
  setState(state) {
    localStorage.setItem('oauth_state', state);
  },
  getState() {
    return localStorage.getItem('oauth_state');
  },
};

// Authenticated Fetch Utility
async function authenticatedFetch(url, options = {}, authContext) {
  let accessToken = TokenStorage.getAccessToken();

  if (TokenStorage.isTokenExpired()) {
    const refreshToken = TokenStorage.getRefreshToken();
    if (refreshToken) {
      try {
        const newTokens = await refreshAccessToken(refreshToken);
        TokenStorage.setTokens(newTokens);
        accessToken = newTokens.access_token;
      } catch (error) {
        if (authContext) {
          authContext.logout();
        }
        throw new Error('Session expired. Please log in again.');
      }
    } else {
      if (authContext) {
        authContext.logout();
      }
      throw new Error('No refresh token available. Please log in again.');
    }
  }

  const headers = {
    ...options.headers,
    Authorization: `Bearer ${accessToken}`,
    'Content-Type': 'application/json',
  };

  const response = await fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
    ...options,
    headers,
  });

  if (response.status === 401) {
    const refreshToken = TokenStorage.getRefreshToken();
    if (refreshToken) {
      try {
        const newTokens = await refreshAccessToken(refreshToken);
        TokenStorage.setTokens(newTokens);
        headers.Authorization = `Bearer ${newTokens.access_token}`;
        return fetch(url.startsWith('http') ? url : `${OAUTH_CONFIG.apiBaseUrl}${url}`, {
          ...options,
          headers,
        });
      } catch (refreshError) {
        if (authContext) {
          authContext.logout();
        }
        throw new Error('Session expired. Please log in again.');
      }
    }
    if (authContext) {
      authContext.logout();
    }
    throw new Error('Unauthorized');
  }

  return response;
}

// Exchange authorization code for tokens
async function exchangeCodeForTokens(code) {
  const codeVerifier = TokenStorage.getCodeVerifier();

  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    client_id: OAUTH_CONFIG.clientId,
    code_verifier: codeVerifier,
  });

  if (OAUTH_CONFIG.clientSecret) {
    body.append('client_secret', OAUTH_CONFIG.clientSecret);
  }

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error_description || errorData.error || 'Token exchange failed');
  }

  return response.json();
}

// Refresh access token
async function refreshAccessToken(refreshToken) {
  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: OAUTH_CONFIG.clientId,
  });

  if (OAUTH_CONFIG.clientSecret) {
    body.append('client_secret', OAUTH_CONFIG.clientSecret);
  }

  const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: body.toString(),
  });

  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.error_description || errorData.error || 'Token refresh failed');
  }

  return response.json();
}

// Auth Context
const AuthContext = createContext(null);

function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

// Auth Provider Component
function AuthProvider({ children }) {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);

  const fetchUserProfile = useCallback(async () => {
    try {
      const response = await authenticatedFetch('/userinfo');
      if (response.ok) {
        const userData = await response.json();
        setUser(userData);
      }
    } catch (err) {
      console.error('Failed to fetch user profile:', err);
    }
  }, []);

  useEffect(() => {
    const initializeAuth = async () => {
      const accessToken = TokenStorage.getAccessToken();
      if (accessToken && !TokenStorage.isTokenExpired()) {
        setIsAuthenticated(true);
        await fetchUserProfile();
      } else if (TokenStorage.getRefreshToken()) {
        try {
          const newTokens = await refreshAccessToken(TokenStorage.getRefreshToken());
          TokenStorage.setTokens(newTokens);
          setIsAuthenticated(true);
          await fetchUserProfile();
        } catch (err) {
          TokenStorage.clearTokens();
          setIsAuthenticated(false);
        }
      }
      setIsLoading(false);
    };

    initializeAuth();
  }, [fetchUserProfile]);

  const login = useCallback(async () => {
    try {
      setError(null);
      const state = generateRandomString(32);
      const codeVerifier = generateRandomString(64);
      const codeChallenge = await generateCodeChallenge(codeVerifier);

      TokenStorage.setState(state);
      TokenStorage.setCodeVerifier(codeVerifier);

      const params = new URLSearchParams({
        response_type: 'code',
        client_id: OAUTH_CONFIG.clientId,
        redirect_uri: OAUTH_CONFIG.redirectUri,
        scope: OAUTH_CONFIG.scope,
        state,
        code_challenge: codeChallenge,
        code_challenge_method: 'S256',
      });

      window.location.href = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
    } catch (err) {
      setError('Failed to initiate login: ' + err.message);
    }
  }, []);

  const handleCallback = useCallback(async (code, state) => {
    try {
      setIsLoading(true);
      setError(null);

      const savedState = TokenStorage.getState();
      if (state !== savedState) {
        throw new Error('State mismatch. Possible CSRF attack.');
      }

      const tokens = await exchangeCodeForTokens(code);
      TokenStorage.setTokens(tokens);
      setIsAuthenticated(true);

      localStorage.removeItem('oauth_code_verifier');
      localStorage.removeItem('oauth_state');

      await fetchUserProfile();

      window.history.replaceState({}, document.title, '/');
    } catch (err) {
      setError('Authentication failed: ' + err.message);
      TokenStorage.clearTokens();
      setIsAuthenticated(false);
    } finally {
      setIsLoading(false);
    }
  }, [fetchUserProfile]);

  const logout = useCallback(() => {
    TokenStorage.clearTokens();
    setIsAuthenticated(false);
    setUser(null);
    setError(null);
    window.history.replaceState({}, document.title, '/');
  }, []);

  const apiFetch = useCallback(
    (url, options) => authenticatedFetch(url, options, { logout }),
    [logout]
  );

  const value = {
    isAuthenticated,
    isLoading,
    user,
    error,
    login,
    logout,
    handleCallback,
    apiFetch,
    clearError: () => setError(null),
  };

  return React.createElement(AuthContext.Provider, { value }, children);
}

// Simple Router
function useRoute() {
  const [path, setPath] = useState(window.location.pathname + window.location.search);

  useEffect(() => {
    const handlePopState = () => {
      setPath(window.location.pathname + window.location.search);
    };
    window.addEventListener('popstate', handlePopState);
    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigate = useCallback((newPath) => {
    window.history.pushState({}, '', newPath);
    setPath(newPath);
  }, []);

  return { path, navigate };
}

